INSERT INTO `v1_b247083602c30e24bd96adad65c19d3dbc9ac8b8ef2c91cc3dadb072c79c15d2` VALUES (6, 11, 0, 113511, 1007001, "あなた様のため…必ずや\n忘れられない最高の夏休みを\nお贈りいたしますわ…", 0, 0, 1007001042, 0, 1);
INSERT INTO `v1_b247083602c30e24bd96adad65c19d3dbc9ac8b8ef2c91cc3dadb072c79c15d2` VALUES ("", 91, "", 0, 1007001, "", "", "", 1007001043, "", "");
