INSERT INTO `v1_b247083602c30e24bd96adad65c19d3dbc9ac8b8ef2c91cc3dadb072c79c15d2` VALUES (6, 11, 0, 113511, 1007001, "はて…？　私は来年の夏も\n一緒に過ごすので思い出して\nいただく必要はないのですが…", 0, 0, 1007001052, 0, 1);
