INSERT INTO `v1_b247083602c30e24bd96adad65c19d3dbc9ac8b8ef2c91cc3dadb072c79c15d2` VALUES (5, 11, 0, 113511, 1007005, "静かな島で弟くんと暮らす…\nここは本当に天国だね。", 0, 0, 1007005040, 0, 1);
