INSERT INTO `v1_b247083602c30e24bd96adad65c19d3dbc9ac8b8ef2c91cc3dadb072c79c15d2` VALUES (6, 11, 0, 113411, 1007005, "これを幸せと呼ばずして\n何を幸せと呼べば\nよいのでしょう…", 0, 0, 1007005045, 0, 1);
