INSERT INTO `v1_b247083602c30e24bd96adad65c19d3dbc9ac8b8ef2c91cc3dadb072c79c15d2` VALUES (6, 11, 0, 113411, 1007007, "そもそも、あなた様からの\nボールを落とすなんて、絶対に\nあってはいけませんわ…", 0, 0, 1007007028, 0, 1);
